export function lst_flyscreen_product_label(p?: Record<string, string | number>): string { return _t(["Produkt","Product","Ürün"], p); }
export function lst_flyscreen_badge(p?: Record<string, string | number>): string { return _t(["Montage in Sankt Augustin","Installation in Sankt Augustin","Sankt Augustin'de montaj"], p); }
export function lst_flyscreen_title(p?: Record<string, string | number>): string { return _t(["Fliegengitter","Fly screens","Sineklikler"], p); }
export function lst_flyscreen_p1(p?: Record<string, string | number>): string { return _t(["Schützen Sie Ihr Zuhause zuverlässig vor Fliegen, Mücken und anderen Insekten – ohne auf Frischluft verzichten zu müssen. Unsere Fliegengitter werden passgenau für Ihre Fenster und Türen gefertigt und professionell montiert.","Protect your home reliably from flies, mosquitoes and other insects – without having to give up fresh air. Our fly screens are custom-made for your windows and doors and professionally installed.","Evinizi sinekler, sivrisinekler ve diğer böceklerden güvenilir biçimde koruyun – taze havadan vazgeçmeden. Sinekliklerimiz pencereleriniz ve kapılarınız için özel olarak üretilir ve profesyonelce monte edilir."], p); }
export function lst_flyscreen_p2(p?: Record<string, string | number>): string { return _t(["Gerade in der Rhein-Sieg-Region, mit ihrer Lage zwischen Flüssen, Feldern und Grünflächen, sorgt ein guter Insektenschutz für echten Mehrwert im Alltag – besonders in den Sommermonaten.","Especially in the Rhein-Sieg region, with its location between rivers, fields and green spaces, good insect protection adds real value to everyday life – particularly in the summer months.","Özellikle nehirler, tarlalar ve yeşil alanlar arasındaki konumuyla Rhein-Sieg bölgesinde, iyi bir böcek koruması günlük yaşama gerçek değer katar – özellikle yaz aylarında."], p); }
export function lst_flyscreen_variants_label(p?: Record<string, string | number>): string { return _t(["Erhältlich als","Available as","Mevcut seçenekler"], p); }
export function lst_flyscreen_v1(p?: Record<string, string | number>): string { return _t(["Spannrahmen für Fenster aller Größen","Tension frames for windows of all sizes","Her boyutta pencere için germe çerçeveler"], p); }
export function lst_flyscreen_v2(p?: Record<string, string | number>): string { return _t(["Dreh- und Pendeltüren für Balkone & Terrassen","Swing and pendulum doors for balconies & terraces","Balkonlar ve teraslar için döner ve sarkıt kapılar"], p); }
export function lst_flyscreen_v3(p?: Record<string, string | number>): string { return _t(["Rollsysteme für Dachfenster und Velux","Roller systems for skylights and Velux","Çatı pencereleri ve Velux için rulo sistemler"], p); }
export function lst_flyscreen_v4(p?: Record<string, string | number>): string { return _t(["Schiebesysteme für große Glasfronten","Sliding systems for large glass fronts","Büyük cam cepheler için sürgülü sistemler"], p); }
export function lst_flyscreen_v5(p?: Record<string, string | number>): string { return _t(["Lichtschachtabdeckungen gegen Insekten & Schmutz","Light well covers against insects & dirt","Böcekler ve kire karşı ışık kuyusu kapakları"], p); }
export function lst_flyscreen_cta(p?: Record<string, string | number>): string { return _t(["Jetzt anfragen","Request now","Şimdi sorgula"], p); }
export function lst_custom_product_label(p?: Record<string, string | number>): string { return _t(["Produkt","Product","Ürün"], p); }
export function lst_custom_title(p?: Record<string, string | number>): string { return _t(["Fliegengitter nach Maß","Custom fly screens","Özel ölçü sineklik"], p); }
export function lst_custom_p1(p?: Record<string, string | number>): string { return _t(["Nicht jedes Fenster ist gleich. Sondermaße, Dachfenster, schräge Öffnungen oder alte Gebäude mit ungewöhnlichen Proportionen – für Standardprodukte aus dem Baumarkt eine echte Herausforderung.","Not every window is the same. Special sizes, skylights, angled openings or old buildings with unusual proportions – a real challenge for standard products from the hardware store.","Her pencere aynı değildir. Özel boyutlar, çatı pencereleri, açılı boşluklar veya alışılmadık oranlara sahip eski binalar – yapı marketinden standart ürünler için gerçek bir zorluk."], p); }
export function lst_custom_p2(p?: Record<string, string | number>): string { return _t(["Unsere Maßanfertigungen sitzen perfekt: kein Klappern, keine Lücken, kein Kompromiss bei der Optik. Jedes Stück wird auf den Millimeter genau gefertigt und passt sich dem Fensterbild harmonisch an.","Our custom-made products fit perfectly: no rattling, no gaps, no compromise on appearance. Each piece is manufactured to the millimetre and fits harmoniously into the window picture.","Özel üretimlerimiz mükemmel oturur: tıkırtı yok, boşluk yok, görünümde taviz yok. Her parça milimetre hassasiyetinde üretilir ve pencere görünümüne uyumlu şekilde entegre olur."], p); }
export function lst_custom_areas_label(p?: Record<string, string | number>): string { return _t(["Typische Einsatzbereiche","Typical applications","Tipik kullanım alanları"], p); }
export function lst_custom_a1(p?: Record<string, string | number>): string { return _t(["Sonderformen und nicht-rechtwinklige Öffnungen","Special shapes and non-rectangular openings","Özel şekiller ve dikdörtgen olmayan açıklıklar"], p); }
export function lst_custom_a2(p?: Record<string, string | number>): string { return _t(["Dachfenster jeder Marke und Neigung","Skylights of any brand and pitch","Her marka ve eğimde çatı pencereleri"], p); }
export function lst_custom_a3(p?: Record<string, string | number>): string { return _t(["Wintergärten und Glasdächer","Conservatories and glass roofs","Kış bahçeleri ve cam çatılar"], p); }
export function lst_custom_a4(p?: Record<string, string | number>): string { return _t(["Historische Gebäude mit ungewöhnlichen Maßen","Historic buildings with unusual dimensions","Alışılmadık ölçülere sahip tarihi binalar"], p); }
export function lst_custom_a5(p?: Record<string, string | number>): string { return _t(["Gewerberäume mit großen Öffnungen","Commercial premises with large openings","Büyük açıklıklı ticari alanlar"], p); }
export function lst_custom_cta(p?: Record<string, string | number>): string { return _t(["Maßanfertigung anfragen","Request custom manufacturing","Özel üretim talebi"], p); }
export function lst_plissee_type_label(p?: Record<string, string | number>): string { return _t(["Produkttyp","Product type","Ürün türü"], p); }
export function lst_plissee_title(p?: Record<string, string | number>): string { return _t(["Plissee-Fliegengitter","Pleated fly screens","Pilise sineklik"], p); }
export function lst_plissee_p1(p?: Record<string, string | number>): string { return _t(["Plissee-Systeme kombinieren maximalen Komfort mit elegantem Design. Der akkordeonartig gefaltete Gewebestreifen zieht sich beim Öffnen platzsparend zur Seite – ideal für Türen, die täglich mehrfach genutzt werden.","Pleated systems combine maximum comfort with elegant design. The accordion-folded fabric strip folds neatly to the side when opened – ideal for doors that are used multiple times a day.","Pilise sistemler maksimum konforu zarif tasarımla birleştirir. Akordeona benzer şekilde katlanan kumaş şerit açıldığında yer tasarrufu yaparak yana çekilir – günde birçok kez kullanılan kapılar için idealdir."], p); }
export function lst_plissee_p2(p?: Record<string, string | number>): string { return _t(["Besonders beliebt für Balkontüren und Terrassenzugänge: kein störendes Rahmenwerk im Blickfeld, freier Durchgang, voller Insektenschutz.","Particularly popular for balcony doors and terrace entrances: no obstructive framework in view, free passage, full insect protection.","Balkon kapıları ve teras girişleri için özellikle popüler: görüş alanında rahatsız edici çerçeve yok, serbest geçiş, tam böcek koruması."], p); }
export function lst_plissee_li1(p?: Record<string, string | number>): string { return _t(["Platzsparend – faltet sich vollständig zusammen","Space-saving – folds up completely","Yer tasarruflu – tamamen katlanır"], p); }
export function lst_plissee_li2(p?: Record<string, string | number>): string { return _t(["Keine Bodenschiene notwendig","No floor rail necessary","Zemin rayı gerekmez"], p); }
export function lst_plissee_li3(p?: Record<string, string | number>): string { return _t(["Für Breiten bis ca. 1,60 m als Einzelflügel","For widths up to approx. 1.60 m as single panel","Tek kanat olarak yaklaşık 1,60 m genişliğe kadar"], p); }
export function lst_plissee_li4(p?: Record<string, string | number>): string { return _t(["Als Doppelplissee auch für breitere Öffnungen","As double pleated screen also for wider openings","Çift pilise olarak daha geniş açıklıklar için de"], p); }
export function lst_sliding_product_label(p?: Record<string, string | number>): string { return _t(["Produkt","Product","Ürün"], p); }
export function lst_sliding_badge(p?: Record<string, string | number>): string { return _t(["Laufruhig & maßgefertigt","Smooth running & custom-made","Sessiz çalışma ve özel üretim"], p); }
export function lst_sliding_h2_pre(p?: Record<string, string | number>): string { return _t(["Verschiebbare","Sliding","Sürgülü"], p); }
export function lst_sliding_h2_post(p?: Record<string, string | number>): string { return _t(["Fliegengitter","fly screens","sineklikler"], p); }
export function lst_sliding_p1(p?: Record<string, string | number>): string { return _t(["Große Glasfronten und breite Terrassentüren sind klassische Schwachstellen beim Insektenschutz. Verschiebbare Systeme schließen diese Lücke zuverlässig – ohne Komforteinbußen.","Large glass fronts and wide terrace doors are classic weak points for insect protection. Sliding systems close this gap reliably – without any loss of comfort.","Büyük cam cepheler ve geniş teras kapıları, böcek korumasında klasik zayıf noktalardır. Sürgülü sistemler bu açığı güvenilir biçimde kapatır – konfor kaybı olmadan."], p); }
export function lst_sliding_p2(p?: Record<string, string | number>): string { return _t(["Der robuste Aluminiumrahmen mit eingespanntem Insektenschutzgewebe gleitet leise auf einem hochwertigen Schienensystem. Ein- oder mehrflügelig, je nach Öffnungsbreite – wir fertigen exakt nach Ihren Gegebenheiten.","The robust aluminium frame with tensioned insect screen mesh glides silently on a high-quality rail system. Single or multi-panel, depending on the opening width – we manufacture exactly to your specifications.","Gerili böcek koruması ağıyla sağlam alüminyum çerçeve, yüksek kaliteli bir ray sisteminde sessizce kayar. Açıklık genişliğine göre tek veya çok kanatlı – tam olarak sizin koşullarınıza göre üretiriz."], p); }
export function lst_sliding_fits_label(p?: Record<string, string | number>): string { return _t(["Geeignet für","Suitable for","Uygun olduğu yerler"], p); }
export function lst_sliding_f1(p?: Record<string, string | number>): string { return _t(["Für Öffnungen von 0,5 bis über 5 Meter Breite","For openings from 0.5 to over 5 metres wide","0,5 ila 5 metreden fazla genişlikteki açıklıklar için"], p); }
export function lst_sliding_f2(p?: Record<string, string | number>): string { return _t(["Ein- und mehrflügelige Konfigurationen","Single and multi-panel configurations","Tek ve çok kanatlı konfigürasyonlar"], p); }
export function lst_sliding_f3(p?: Record<string, string | number>): string { return _t(["Laufruhiges, wartungsarmes Schienensystem","Smooth-running, low-maintenance rail system","Sessiz çalışan, az bakım gerektiren ray sistemi"], p); }
export function lst_sliding_f4(p?: Record<string, string | number>): string { return _t(["Dezentes Design, verschiedene Farben wählbar","Discreet design, various colours available","Sade tasarım, çeşitli renk seçenekleri"], p); }
export function lst_sliding_f5(p?: Record<string, string | number>): string { return _t(["Langlebig und witterungsbeständig","Durable and weatherproof","Dayanıklı ve hava koşullarına dirençli"], p); }
