export function lst_materials_label(p?: Record<string, string | number>): string { return _t(["Qualität","Quality","Kalite"], p); }
export function lst_materials_h2_pre(p?: Record<string, string | number>): string { return _t(["Materialien &","Materials &","Malzemeler ve"], p); }
export function lst_materials_h2_post(p?: Record<string, string | number>): string { return _t(["Ausstattungsoptionen","equipment options","donanım seçenekleri"], p); }
export function lst_materials_desc(p?: Record<string, string | number>): string { return _t(["Wir setzen auf hochwertige Materialien, die langlebig, wartungsarm und optisch ansprechend sind. Je nach Bedarf und Anwendungsfall beraten wir Sie zur optimalen Kombination.","We use high-quality materials that are durable, low-maintenance and visually appealing. Depending on your needs and application, we will advise you on the optimal combination.","Dayanıklı, az bakım gerektiren ve görsel açıdan çekici yüksek kaliteli malzemeler kullanıyoruz. İhtiyacınıza ve kullanım durumunuza göre en uygun kombinasyon için size danışıyoruz."], p); }
export function lst_mat_alu_title(p?: Record<string, string | number>): string { return _t(["Aluminiumrahmen","Aluminium frames","Alüminyum çerçeveler"], p); }
export function lst_mat_alu_desc(p?: Record<string, string | number>): string { return _t(["Leicht, stabil und witterungsbeständig. Erhältlich in verschiedenen Farben und Oberflächen.","Light, stable and weatherproof. Available in various colours and finishes.","Hafif, sağlam ve hava koşullarına dayanıklı. Çeşitli renk ve yüzey seçeneklerinde mevcut."], p); }
export function lst_mat_fiber_title(p?: Record<string, string | number>): string { return _t(["Fiberglas-Gewebe","Fibreglass mesh","Fiberglas ağ"], p); }
export function lst_mat_fiber_desc(p?: Record<string, string | number>): string { return _t(["Besonders feinmaschig, UV-beständig und leicht reinigbar. Der Klassiker für Fenster und Türen.","Particularly fine-meshed, UV-resistant and easy to clean. The classic choice for windows and doors.","Özellikle ince gözenekli, UV'ye dayanıklı ve kolay temizlenir. Pencereler ve kapılar için klasik tercih."], p); }
export function lst_mat_steel_title(p?: Record<string, string | number>): string { return _t(["Edelstahl-Gewebe","Stainless steel mesh","Paslanmaz çelik ağ"], p); }
export function lst_mat_steel_desc(p?: Record<string, string | number>): string { return _t(["Extrem robust, kratzfest und ideal für stark beanspruchte Bereiche oder Haustierbesitzer.","Extremely robust, scratch-resistant and ideal for heavily used areas or pet owners.","Son derece sağlam, çizilmez ve yoğun kullanılan alanlar veya evcil hayvan sahipleri için idealdir."], p); }
export function lst_mat_pollen_title(p?: Record<string, string | number>): string { return _t(["Pollenschutzgewebe","Pollen protection mesh","Polen koruma ağı"], p); }
export function lst_mat_pollen_desc(p?: Record<string, string | number>): string { return _t(["Bis zu 80 % der Pollen werden zurückgehalten – ideal für Allergiker.","Up to 80 % of pollen is filtered out – ideal for allergy sufferers.","Polenlerin yüzde 80'ine kadarı tutulur – alerjisi olanlar için idealdir."], p); }
export function lst_mat_pet_title(p?: Record<string, string | number>): string { return _t(["Haustierlösungen","Pet solutions","Evcil hayvan çözümleri"], p); }
export function lst_mat_pet_desc(p?: Record<string, string | number>): string { return _t(["Kratzfestes Gewebe und optionale Katzenklappe – damit auch Vierbeiner kein Problem sind.","Scratch-resistant mesh and optional cat flap – so that four-legged friends are no problem either.","Çizilmez ağ ve isteğe bağlı kedi kapısı – böylece dört ayaklı dostlar da sorun olmaz."], p); }
export function lst_mat_drill_title(p?: Record<string, string | number>): string { return _t(["Montage ohne Bohren","Installation without drilling","Delme olmadan montaj"], p); }
export function lst_mat_drill_desc(p?: Record<string, string | number>): string { return _t(["Mietfreundliche Befestigung möglich – ideal für Mieter und denkmalgeschützte Gebäude.","Tenant-friendly fixing possible – ideal for tenants and listed buildings.","Kiracı dostu montaj mümkün – kiracılar ve tescilli binalar için idealdir."], p); }
export function lst_target_private_title(p?: Record<string, string | number>): string { return _t(["Privatkunden","Private customers","Bireysel müşteriler"], p); }
export function lst_target_private_desc(p?: Record<string, string | number>): string { return _t(["Für Haus- und Wohnungsbesitzer sowie Mieter – mit oder ohne Bohren, für jedes Fenster und jede Tür, auch für Besonderheiten wie Dachfenster oder alte Gebäude.","For home and flat owners as well as tenants – with or without drilling, for every window and door, also for special features such as skylights or old buildings.","Ev ve daire sahipleri ile kiracılar için – delme ile veya deliksiz, her pencere ve kapı için, çatı pencereleri veya eski binalar gibi özellikler dahil."], p); }
export function lst_target_business_title(p?: Record<string, string | number>): string { return _t(["Gewerbekunden","Commercial customers","Ticari müşteriler"], p); }
export function lst_target_business_desc(p?: Record<string, string | number>): string { return _t(["Für Büros, Gaststätten, Praxen und andere Gewerbeflächen – schnelle Umsetzung auch bei größeren Projekten mit mehreren Fenstern und Türen.","For offices, restaurants, practices and other commercial premises – fast implementation even for larger projects with multiple windows and doors.","Ofisler, restoranlar, muayenehaneler ve diğer ticari alanlar için – birden fazla pencere ve kapılı büyük projelerde de hızlı uygulama."], p); }
export function lst_process_label(p?: Record<string, string | number>): string { return _t(["Unser Ablauf","Our process","Sürecimiz"], p); }
export function lst_process_h2(p?: Record<string, string | number>): string { return _t(["Von der Anfrage bis zur fertigen Montage","From enquiry to completed installation","Talebin alınmasından montajın tamamlanmasına kadar"], p); }
export function lst_step1_title(p?: Record<string, string | number>): string { return _t(["Kostenlose Beratung vor Ort","Free on-site consultation","Ücretsiz yerinde danışmanlık"], p); }
export function lst_step1_desc(p?: Record<string, string | number>): string { return _t(["Wir kommen zu Ihnen nach Hause oder in Ihre Gewerberäume und schauen uns die Situation gemeinsam an – unverbindlich, ohne versteckte Kosten.","We come to your home or commercial premises and assess the situation together – without obligation, without hidden costs.","Evinize veya ticari alanınıza gelerek durumu birlikte değerlendiriyoruz – bağlayıcılık olmadan, gizli maliyet olmadan."], p); }
export function lst_step2_title(p?: Record<string, string | number>): string { return _t(["Präzise Maßnahme","Precise measurement","Hassas ölçüm"], p); }
export function lst_step2_desc(p?: Record<string, string | number>): string { return _t(["Jedes Maß wird sorgfältig aufgenommen – auf den Millimeter genau. So wird garantiert, dass Ihr Fliegengitter später perfekt sitzt.","Every measurement is carefully taken – to the millimetre. This guarantees that your fly screen will fit perfectly.","Her ölçü dikkatle alınır – milimetre hassasiyetinde. Bu, sinekliğinizin daha sonra mükemmel oturmasını garanti eder."], p); }
export function lst_step3_title(p?: Record<string, string | number>): string { return _t(["Individuelle Fertigung","Individual manufacturing","Bireysel üretim"], p); }
export function lst_step3_desc(p?: Record<string, string | number>): string { return _t(["Auf Basis Ihrer Maße wird jedes Produkt einzeln gefertigt. Kein Konfektionsartikel, sondern echte Maßanfertigung aus hochwertigen Materialien.","Based on your measurements, each product is manufactured individually. No off-the-shelf item, but genuine custom manufacturing from high-quality materials.","Ölçülerinize göre her ürün ayrı ayrı üretilir. Hazır ürün değil, yüksek kaliteli malzemelerden gerçek özel üretim."], p); }
export function lst_step4_title(p?: Record<string, string | number>): string { return _t(["Professionelle Montage","Professional installation","Profesyonel montaj"], p); }
export function lst_step4_desc(p?: Record<string, string | number>): string { return _t(["Wir bringen Ihre Fliegengitter fachgerecht an – inklusive Einweisung, Funktionskontrolle und direktem Ansprechpartner bei Fragen.","We install your fly screens professionally – including a briefing, functional check and a direct contact person for any questions.","Sinekliklerinizi profesyonelce monte ediyoruz – tanıtım, işlevsellik kontrolü ve sorularınız için doğrudan iletişim kişisi dahil."], p); }
export function lst_cta_label(p?: Record<string, string | number>): string { return _t(["Kostenlose Beratung","Free consultation","Ücretsiz danışmanlık"], p); }
export function lst_cta_h2(p?: Record<string, string | number>): string { return _t(["Bereit für Ihren Schutz?","Ready for your protection?","Korumanız için hazır mısınız?"], p); }
export function lst_cta_desc(p?: Record<string, string | number>): string { return _t(["Wir kommen zu Ihnen, schauen uns alles an und beraten Sie kostenlos und unverbindlich. Rufen Sie uns an oder schreiben Sie uns – wir melden uns schnell zurück.","We come to you, look at everything and advise you free of charge and without obligation. Call us or write to us – we will get back to you quickly.","Size geliyoruz, her şeye bakıyor ve sizi ücretsiz ve bağlayıcılık olmadan danışıyoruz. Bizi arayın veya yazın – hızlıca geri döneceğiz."], p); }
