export function ref_head_desc(p?: Record<string, string | number>): string { return _t(["Referenzbilder von Insektenschutz Rhein-Sieg in Sankt Augustin – Fliegengitter, Maßanfertigung und verschiebbare Systeme in der Praxis.","Reference images from Insektenschutz Rhein-Sieg in Sankt Augustin – fly screens, custom manufacturing and sliding systems in practice.","Sankt Augustin'den Insektenschutz Rhein-Sieg'in referans görselleri – pratikte sineklikler, özel üretim ve sürgülü sistemler."], p); }
