export function ref_cta_desc(p?: Record<string, string | number>): string { return _t(["Wir beraten Sie kostenlos vor Ort, nehmen Maß und fertigen Ihre individuelle Lösung. Rufen Sie uns an oder stellen Sie direkt eine Anfrage.","We advise you free of charge on-site, take measurements and manufacture your individual solution. Call us or send a direct request.","Sizi ücretsiz yerinde danışıyor, ölçü alıyor ve bireysel çözümünüzü üretiyoruz. Bizi arayın veya doğrudan talep gönderin."], p); }
export function uu_head_title(p?: Record<string, string | number>): string { return _t(["Über uns – Insektenschutz Rhein-Sieg","About us – Insektenschutz Rhein-Sieg","Hakkımızda – Insektenschutz Rhein-Sieg"], p); }
export function uu_head_desc(p?: Record<string, string | number>): string { return _t(["Insektenschutz Rhein-Sieg in Sankt Augustin – Ihr regionaler Experte für Fliegengitter und Insektenschutz. Inhaber Taner Özyurt bietet Beratung, Maßanfertigung und Montage.","Insektenschutz Rhein-Sieg in Sankt Augustin – your regional expert for fly screens and insect protection. Owner Taner Özyurt offers consultation, custom manufacturing and installation.","Sankt Augustin'de Insektenschutz Rhein-Sieg – sineklik ve böcek koruması için bölgesel uzmanınız. Sahip Taner Özyurt danışmanlık, özel üretim ve montaj sunmaktadır."], p); }
export function uu_hero_label(p?: Record<string, string | number>): string { return _t(["Über uns","About us","Hakkımızda"], p); }
export function uu_hero_h1_pre(p?: Record<string, string | number>): string { return _t(["Ihr regionaler Experte","Your regional expert","Bölgesel uzmanınız"], p); }
export function uu_hero_h1_mid(p?: Record<string, string | number>): string { return _t(["für Insektenschutz","for insect protection","böcek koruması için"], p); }
export function uu_hero_h1_post(p?: Record<string, string | number>): string { return _t(["im Rhein-Sieg-Kreis","in the Rhein-Sieg district","Rhein-Sieg ilçesinde"], p); }
export function uu_hero_desc(p?: Record<string, string | number>): string { return _t(["Insektenschutz Rhein-Sieg steht für persönlichen Service, handwerkliche Qualität und maßgefertigte Lösungen – direkt vor Ihrer Haustür in Sankt Augustin und der gesamten Region.","Insektenschutz Rhein-Sieg stands for personal service, craftsman quality and custom-made solutions – right on your doorstep in Sankt Augustin and the entire region.","Insektenschutz Rhein-Sieg kişisel hizmet, zanaatkâr kalitesi ve özel çözümler için bilinir – Sankt Augustin ve tüm bölgede kapınızın hemen önünde."], p); }
export function uu_company_label(p?: Record<string, string | number>): string { return _t(["Das Unternehmen","The company","Şirket"], p); }
export function uu_company_h2(p?: Record<string, string | number>): string { return _t(["Handwerk mit Leidenschaft und Regionalität","Craftsmanship with passion and regional roots","Tutku ve yerellikle zanaatkârlık"], p); }
export function uu_company_p1(p?: Record<string, string | number>): string { return _t(["Insektenschutz Rhein-Sieg ist ein inhabergeführter Fachbetrieb mit Sitz in {location}. Inhaber {owner} hat sich auf maßgefertigten Insektenschutz spezialisiert – von einfachen Spannrahmen bis hin zu verschiebbaren Systemen für große Glasfronten und Wintergärten.","Insektenschutz Rhein-Sieg is an owner-managed specialist business based in {location}. Owner {owner} has specialised in custom-made insect protection – from simple tension frames to sliding systems for large glass fronts and conservatories.","Insektenschutz Rhein-Sieg, merkezi {location}'de olan sahip yönetiminde uzman bir işletmedir. Sahip {owner}, basit germe çerçevelerden büyük cam cepheler ve kış bahçeleri için sürgülü sistemlere kadar özel böcek korumasında uzmanlaşmıştır."], p); }
export function uu_company_p2(p?: Record<string, string | number>): string { return _t(["Unser Anspruch: Jede Lösung soll perfekt passen – optisch, funktional und langlebig. Wir setzen auf persönliche Beratung vor Ort, präzise Maßnahme und fachgerechte Montage. Keine Kompromisse bei Qualität und Passform.","Our standard: every solution should fit perfectly – visually, functionally and durably. We rely on personal on-site consultation, precise measurement and professional installation. No compromises on quality and fit.","Standardımız: her çözüm mükemmel oturmalı – görsel, işlevsel ve dayanıklılık açısından. Kişisel yerinde danışmanlık, hassas ölçüm ve profesyonel montaja güveniyoruz. Kalite ve uyum konusunda taviz yok."], p); }
export function uu_company_p3(p?: Record<string, string | number>): string { return _t(["Als regionaler Betrieb kennen wir die Besonderheiten der Rhein-Sieg-Region – die Lage zwischen Rhein, Sieg, Feldern und Grünflächen sorgt für erhöhten Insektendruck, besonders in den Sommermonaten. Wir bieten Lösungen, die wirklich schützen.","As a regional business, we know the particularities of the Rhein-Sieg region – the location between the Rhine, Sieg, fields and green spaces creates increased insect pressure, especially in the summer months. We offer solutions that really protect.","Bölgesel bir işletme olarak Rhein-Sieg bölgesinin özelliklerini biliyoruz – Ren, Sieg, tarlalar ve yeşil alanlar arasındaki konum özellikle yaz aylarında artan böcek baskısına neden olur. Gerçekten koruyan çözümler sunuyoruz."], p); }
