export function uu_val1_title(p?: Record<string, string | number>): string { return _t(["Kostenlose Vor-Ort-Beratung","Free on-site consultation","Ücretsiz yerinde danışmanlık"], p); }
export function uu_val1_desc(p?: Record<string, string | number>): string { return _t(["Wir kommen zu Ihnen nach Hause und beraten Sie unverbindlich – ohne versteckte Kosten.","We come to your home and advise you without obligation – without hidden costs.","Evinize geliyor ve sizi bağlayıcılık olmadan danışıyoruz – gizli maliyet yok."], p); }
export function uu_val2_title(p?: Record<string, string | number>): string { return _t(["Maßanfertigung auf den Millimeter","Custom-made to the millimetre","Milimetre hassasiyetinde özel üretim"], p); }
export function uu_val2_desc(p?: Record<string, string | number>): string { return _t(["Jedes Fliegengitter wird individuell für Ihr Fenster, Ihre Tür oder Ihr Dachfenster gefertigt.","Every fly screen is individually manufactured for your window, door or skylight.","Her sineklik pencereniz, kapınız veya çatı pencereniz için bireysel olarak üretilir."], p); }
export function uu_val3_title(p?: Record<string, string | number>): string { return _t(["Vollservice aus einer Hand","Full service from one source","Tek elden tam hizmet"], p); }
export function uu_val3_desc(p?: Record<string, string | number>): string { return _t(["Von der Beratung über die Maßanfertigung bis zur professionellen Montage – alles aus einer Hand.","From consultation to custom manufacturing to professional installation – everything from one source.","Danışmanlıktan özel üretime ve profesyonel montaja kadar – her şey tek elden."], p); }
export function uu_val4_title(p?: Record<string, string | number>): string { return _t(["Hochwertige Materialien","High-quality materials","Yüksek kaliteli malzemeler"], p); }
export function uu_val4_desc(p?: Record<string, string | number>): string { return _t(["Aluminiumrahmen, Edelstahl- und Fiberglas-Gewebe sowie optional Pollenschutzfilter und Haustierlösungen.","Aluminium frames, stainless steel and fibreglass mesh, plus optional pollen protection filter and pet solutions.","Alüminyum çerçeveler, paslanmaz çelik ve fiberglas ağ ile isteğe bağlı polen koruma filtresi ve evcil hayvan çözümleri."], p); }
export function uu_val5_title(p?: Record<string, string | number>): string { return _t(["Mietfreundliche Montage","Tenant-friendly installation","Kiracı dostu montaj"], p); }
export function uu_val5_desc(p?: Record<string, string | number>): string { return _t(["Auf Wunsch montieren wir ohne Bohren – ideal für Mieter und Mietwohnungen.","On request, we install without drilling – ideal for tenants and rented flats.","İstek üzerine delme olmadan monte ediyoruz – kiracılar ve kiralık daireler için idealdir."], p); }
export function uu_val6_title(p?: Record<string, string | number>): string { return _t(["Privat & gewerblich","Private & commercial","Bireysel ve ticari"], p); }
export function uu_val6_desc(p?: Record<string, string | number>): string { return _t(["Wir betreuen sowohl Privatpersonen als auch gewerbliche Kunden in der gesamten Region.","We serve both private individuals and commercial customers throughout the region.","Bölge genelinde hem bireysel müşterilere hem de ticari müşterilere hizmet veriyoruz."], p); }
export function uu_area_label(p?: Record<string, string | number>): string { return _t(["Servicegebiet","Service area","Hizmet alanı"], p); }
export function uu_area_h2(p?: Record<string, string | number>): string { return _t(["Für Sie in der Region unterwegs","Active in the region for you","Bölgede sizin için aktif"], p); }
export function uu_area_p(p?: Record<string, string | number>): string { return _t(["Wir sind im Rhein-Sieg-Kreis und der weiteren Region rund um Bonn und Köln für Sie aktiv. Unser Heimatstandort ist Sankt Augustin – von dort aus erreichen wir alle wichtigen Orte in der Region schnell und unkompliziert.","We are active in the Rhein-Sieg district and the wider region around Bonn and Cologne for you. Our home base is Sankt Augustin – from there we reach all important locations in the region quickly and easily.","Rhein-Sieg ilçesinde ve Bonn ile Köln çevresindeki geniş bölgede sizin için aktifiz. Ana üssümüz Sankt Augustin – oradan bölgedeki tüm önemli yerlere hızlı ve kolay ulaşıyoruz."], p); }
