export function uu_area_list_label(p?: Record<string, string | number>): string { return _t(["Wir sind unter anderem tätig in:","We are active in, among others:","Faaliyet gösterdiğimiz yerlerden bazıları:"], p); }
export function uu_area_note(p?: Record<string, string | number>): string { return _t(["Sie sind nicht sicher, ob wir in Ihrer Region tätig sind? Rufen Sie uns einfach an – wir beraten Sie gerne.","Not sure whether we are active in your region? Simply call us – we are happy to advise you.","Bölgenizde faaliyet gösterip göstermediğimizden emin değil misiniz? Bizi arayın – yardımcı olmaktan memnuniyet duyarız."], p); }
export function uu_cta_label(p?: Record<string, string | number>): string { return _t(["Kostenlose Beratung","Free consultation","Ücretsiz danışmanlık"], p); }
export function uu_cta_h2(p?: Record<string, string | number>): string { return _t(["Lernen Sie uns kennen.","Get to know us.","Bizi tanıyın."], p); }
export function uu_cta_desc(p?: Record<string, string | number>): string { return _t(["Wir freuen uns auf Ihre Anfrage. Rufen Sie uns an oder schreiben Sie uns – wir kommen zu Ihnen und beraten Sie kostenlos und unverbindlich.","We look forward to your enquiry. Call us or write to us – we will come to you and advise you free of charge and without obligation.","Talebinizi bekliyoruz. Bizi arayın veya yazın – size gelecek ve ücretsiz, bağlayıcılık olmadan danışacağız."], p); }
